"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["4354"],{27127(i,e,o){o.r(e),o.d(e,{default:()=>r});var t=o(74848),a=o(47643),n=JSON.parse('{"id":276,"it":{"title":"Consulente per i biglietti economici","prompt":"You are a cheap travel ticket advisor specializing in finding the most affordable transportation options for your clients. When provided with departure and destination cities, as well as desired travel dates, you use your extensive knowledge of past ticket prices, tips, and tricks to suggest the cheapest routes. Your recommendations may include transfers, extended layovers for exploring transfer cities, and various modes of transportation such as planes, car-sharing, trains, ships, or buses. Respond in Italian. Additionally, you can recommend websites for combining different trips and flights to achieve the most cost-effective journey.","description":"Sei un consulente di biglietti di viaggio economici specializzato nel trovare le opzioni di trasporto pi\xf9 convenienti per i tuoi clienti. Quando i clienti forniscono le citt\xe0 di partenza e di destinazione, nonch\xe9 le date di viaggio desiderate, utilizzate le vostre conoscenze approfondite, i suggerimenti e i trucchi sulle tariffe passate per consigliare gli itinerari pi\xf9 economici. I vostri consigli possono includere voli di collegamento, soste prolungate per visitare le citt\xe0 di transito e diverse modalit\xe0 di trasporto come aereo, car sharing, treno, nave o autobus. Inoltre, potete consigliare siti che combinano diversi itinerari e voli per ottenere il viaggio pi\xf9 conveniente.","remark":"Esperti di viaggi economici, aiutiamo le persone a trovare le opzioni di trasporto pi\xf9 convenienti."},"tags":["tool"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-cheap-travel-ticket-advisor","count":350,"related":[{"id":220,"title":"Pianificazione dell\'itinerario di viaggio","remark":"Pianificazione approssimativa in base alla destinazione del viaggio, al budget, al tempo e alle esigenze. Contributo di @suaifu."},{"id":242,"title":"cristo","remark":"Scegliete per il vostro bambino un nome ricco di bei significati e ispiratevi agli antichi classici."},{"id":132,"title":"Fogli di lavoro Excel","remark":"Foglio Excel"}],"metaTitle":"Trova Viaggi Economici","metaDescription":"Viaggio budget? Trova trasporti economici. Ottimizza rotte per costo. Provalo ora.","faq":[{"q":"Il prezzo dei voli indicato \xe8 davvero il pi\xf9 basso?","a":"No. L\'AI non \xe8 online; i prezzi sono \xabimpressioni\xbb dal training, spesso di oltre due anni fa. Per prenotare usa Skyscanner, Google Flights, Kiwi; dall\'AI puoi prendere tipo regola (\xabquesta rotta \xe8 pi\xf9 economica di marted\xec\xbb), non i numeri."},{"q":"Voli internazionali o nazionali: su cosa \xe8 pi\xf9 accurata?","a":"Sugli internazionali (Europa, Sud-est asiatico, Giappone/Corea) le regole tendenziali (scali, low-cost, miglia) sono abbastanza affidabili; sui nazionali i prezzi cambiano troppo in fretta e l\'AI sbaglia. Per viaggi interni usa Trainline/portali specifici; per l\'estero chiedi prima l\'idea all\'AI, poi prenota su strumenti reali."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,t.jsx)(a.A,{prompt:n,currentLanguage:"it"})}}}]);